import{_ as p,o as t,c as r,b as s,w as o,d as a,e as i,a as c,r as n}from"./app.dec15874.js";const y="/vite-press-blog/assets/ts-understand.7b66e38f.webp",g=JSON.parse('{"title":"说说你对 TypeScript 的理解？与 JavaScript 的区别？","description":"","frontmatter":{"createTime":"2022/10/18","tag":"ts"},"headers":[{"level":2,"title":"一、是什么","slug":"一、是什么","link":"#一、是什么","children":[]},{"level":2,"title":"二、特性","slug":"二、特性","link":"#二、特性","children":[{"level":3,"title":"TypeScript 的特性主要有如下","slug":"typescript-的特性主要有如下","link":"#typescript-的特性主要有如下","children":[]},{"level":3,"title":"类型批注","slug":"类型批注","link":"#类型批注","children":[]},{"level":3,"title":"类型推断","slug":"类型推断","link":"#类型推断","children":[]},{"level":3,"title":"接口","slug":"接口","link":"#接口","children":[]}]},{"level":2,"title":"三、区别","slug":"三、区别","link":"#三、区别","children":[]}],"relativePath":"interview-questions/ts/ts-understand/index.md","lastUpdated":1667281923000}'),d={name:"interview-questions/ts/ts-understand/index.md"},D=a("h1",{id:"说说你对-typescript-的理解-与-javascript-的区别",tabindex:"-1"},[i("说说你对 TypeScript 的理解？与 JavaScript 的区别？ "),a("a",{class:"header-anchor",href:"#说说你对-typescript-的理解-与-javascript-的区别","aria-hidden":"true"},"#")],-1),F=c(`<h2 id="一、是什么" tabindex="-1">一、是什么 <a class="header-anchor" href="#一、是什么" aria-hidden="true">#</a></h2><p>TypeScript 是 JavaScript 的类型的超集，支持ES6语法，支持面向对象编程的概念，如类、接口、继承、泛型等 超集，不得不说另外一个概念，子集，怎么理解这两个呢，举个例子，如果一个集合 A 里面的的所有元素集合 B 里面都存在，那么我们可以理解集合 B 是集合 A 的超集，集合 A 为集合 B 的子集</p><ul><li>其是一种静态类型检查的语言，提供了类型注解，在代码编译阶段就可以检查出数据类型的错误</li><li>同时扩展了 JavaScript 的语法，所以任何现有的 JavaScript 程序可以不加改变的在 TypeScript 下工作</li><li>为了保证兼容性，TypeScript 在编译阶段需要编译器编译成纯 JavaScript 来运行，是为大型应用之开发而设计的语言</li></ul><h2 id="二、特性" tabindex="-1">二、特性 <a class="header-anchor" href="#二、特性" aria-hidden="true">#</a></h2><h3 id="typescript-的特性主要有如下" tabindex="-1">TypeScript 的特性主要有如下 <a class="header-anchor" href="#typescript-的特性主要有如下" aria-hidden="true">#</a></h3><ul><li>类型批注和编译时类型检查 ：在编译时批注变量类型</li><li>类型推断：ts 中没有批注变量类型会自动推断变量的类型</li><li>类型擦除：在编译过程中批注的内容和接口会在运行时利用工具擦除</li><li>接口：ts 中用接口来定义对象类型</li><li>枚举：用于取值被限定在一定范围内的场景</li><li>Mixin：可以接受任意类型的值</li><li>泛型编程：写代码时使用一些以后才指定的类型</li><li>名字空间：名字只在该区域内有效，其他区域可重复使用该名字而不冲突</li><li>元组：元组合并了不同类型的对象，相当于一个可以装不同类型数据的数组</li><li>...</li></ul><h3 id="类型批注" tabindex="-1">类型批注 <a class="header-anchor" href="#类型批注" aria-hidden="true">#</a></h3><p>通过类型批注提供在编译时启动类型检查的静态类型，这是可选的，而且可以忽略而使用 JavaScript 常规的动态类型</p><div class="language-ts line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">function</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">Add</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;font-style:italic;">left</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">number</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#A6ACCD;font-style:italic;">right</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">number</span><span style="color:#89DDFF;">):</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">number</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">left</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">+</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">right</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>对于基本类型的批注是 number、bool 和 string，而弱或动态类型的结构则是 any 类型</p><h3 id="类型推断" tabindex="-1">类型推断 <a class="header-anchor" href="#类型推断" aria-hidden="true">#</a></h3><p>当类型没有给出时，TypeScript 编译器利用类型推断来推断类型，如下：</p><div class="language-ts line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">let</span><span style="color:#A6ACCD;"> str </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">string</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>变量 str 被推断为字符串类型，这种推断发生在初始化变量和成员，设置默认参数值和决定函数返回值时 如果缺乏声明而不能推断出类型，那么它的类型被视作默认的动态 any 类型</p><h3 id="接口" tabindex="-1">接口 <a class="header-anchor" href="#接口" aria-hidden="true">#</a></h3><p>接口简单来说就是用来描述对象的类型 数据的类型有 number、null、 string 等数据格式，对象的类型就是用接口来描述的</p><div class="language-ts line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"></span>
<span class="line"><span style="color:#C792EA;">interface</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Person</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">name</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">string</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">age</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">number</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">let</span><span style="color:#A6ACCD;"> tom</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Person</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">name</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Tom</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">age</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">25</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">};</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="三、区别" tabindex="-1">三、区别 <a class="header-anchor" href="#三、区别" aria-hidden="true">#</a></h2><ul><li>TypeScript 是 JavaScript 的超集，扩展了 JavaScript 的语法</li><li>TypeScript 可处理已有的 JavaScript 代码，并只对其中的 TypeScript 代码进行编译</li><li>TypeScript 文件的后缀名 .ts （.ts，.tsx，.dts），JavaScript 文件是 .js</li><li>在编写 TypeScript 的文件的时候就会自动编译成 js 文件 更多的区别如下图所示： <img src="`+y+'" alt="图片"></li></ul>',19);function C(u,h,A,b,m,v){const l=n("ArticleMetadata"),e=n("ClientOnly");return t(),r("div",null,[D,s(e,null,{default:o(()=>[s(l)]),_:1}),F])}const S=p(d,[["render",C]]);export{g as __pageData,S as default};
